<?php
declare(strict_types=1);require dirname(__DIR__).'/app/core/Env.php';\App\Core\Env::load(dirname(__DIR__).'/.env');spl_autoload_register(function(string $class):void{$prefix='App\\';if(!str_starts_with($class,$prefix))return;$relative=substr($class,strlen($prefix));$parts=explode('\\',$relative);$parts[0]=strtolower($parts[0]);$file=dirname(__DIR__).'/app/'.implode('/',$parts).'.php';if(is_file($file))require_once $file;});use App\Core\Database;$pdo=Database::connection();$rows=$pdo->query("SELECT * FROM inspection_attachments WHERE deleted_at IS NULL AND expires_at IS NOT NULL AND expires_at<NOW()")->fetchAll();$root=dirname(__DIR__).'/storage/uploads/';foreach($rows as $r){foreach(['storage_path','thumbnail_path'] as $k){if(!empty($r[$k])){$p=$root.$r[$k];if(is_file($p))@unlink($p);}}$pdo->prepare('UPDATE inspection_attachments SET deleted_at=NOW() WHERE id=?')->execute([$r['id']]);echo "Pruned attachment #{$r['id']}\n";}
